create table dirkspzm32.isi_system_info (
    sid                    varchar2(2 char) not null enable,
    firma_nr               number(6, 0) not null enable,
    hostname               varchar2(150 char) not null enable,
    betriebssystem         varchar2(255 char),
    appl_caption           varchar2(255 char),
    appl_exe_name          varchar2(255 char) not null enable,
    appl_ordner            varchar2(255 char),
    appl_version           varchar2(20 char),
    appl_umgebung          varchar2(10 char),
    last_run_timestamp     date,
    last_run_os_user       varchar2(100 char) not null enable,
    last_login_id          number(*, 0),
    integrierte_module     varchar2(1000 char),
    status                 varchar2(10 char),
    host_ip_list           varchar2(255 char),
    appl_used_ip           varchar2(50 char),
    last_license_ticket_id number(*, 0),
    last_license_ticket_ts date,
    last_license_valid_sek number(*, 12)
);

alter table dirkspzm32.isi_system_info
    add constraint pk_isi_system_info
        primary key ( sid,
                      firma_nr,
                      hostname,
                      appl_exe_name,
                      last_run_os_user )
            using index enable;


